<main class="dashboard-grid">
    <!-- Sidebar: Controls & Context -->
    <aside class="panel">
        <h1>Habit Dashboard</h1>
        <p class="text-muted">Track your consistency with interactive weekly visualization.</p>

        <div class="controls">
