[showing latest streamed output]
Comparison Mode</span>
            <p>Compare current week performance against your baseline standards.</p>
        </div>

        <div class="insight-box" id="insight-summary" style="display:none;">
            <span class="insight-title">Weekly Summary</span>
            <p>Great job! You completed 5 out of 7 days at 85% average. Keep the momentum going!</p>
        </div>
    </main>
</main>

<script>
    // Toggle evidence layer
    document.getElementById('btn-state-evidence').addEventListener('click', () => {
        document.querySelectorAll('.evidence-layer').forEach(el => el.classList.add('visible'));
        document.getElementById('btn-state-evidence').classList.add('active');
        document.getElementById('btn-state-default').classList.remove('active');
        document.getElementById('insight-evidence').style.display = 'block';
        document.getElementById('insight-default').style.display = 'none';
    });

    // Toggle comparison view
    document.getElementById('btn-state-compare').addEventListener('click', () => {
        document.getElementById('comparison-default').style.display = 'flex';
        document.getElementById('btn-state-compare').classList.add('active');
        document.getElementById('btn-state-default').classList.remove('active');
        document.getElementById('insight-compare').style.display = 'block';
        document.getElementById('insight-default').style.display = 'none';
    });

    // Toggle insights summary
    document.getElementById('btn-state-insights').addEventListener('click', () => {
        document.getElementById('insight-summary').style.display = 'block';
        document.getElementById('btn-state-insights').classList.add('active');
        document.getElementById('btn-state-default').classList.remove('active');
        document.getElementById('insight-default').style.display = 'none';
    });

    // Bar hover effects
    document.querySelectorAll('.bar').forEach(bar => {
        bar.addEventListener('mouseenter', () => {
            bar.style.opacity = '1';
        });
        bar.addEventListener('mouseleave', () => {
            bar.style.opacity = '0.8';
        });
    });
</script>
</body>
</html>

