    // Toggle insights summary
    document.getElementById('btn-state-insights').addEventListener('click', () => {
        document.getElementById('insight-summary').style.display = 'block';
        document.getElementById('btn-state-insights').classList.add('active');
        document.getElementById('btn-state-default').classList.remove('active');
        document.getElementById('insight-default').style.display = 'none';
    });

    // Bar hover effects
    document.querySelectorAll('.bar').forEach(bar => {
        bar.addEventListener('mouseenter', () => {
            bar.style.opacity = '1';
        });
        bar.addEventListener('mouseleave', () => {
            bar.style.opacity = '0.8';
        });
    });
